	seedPlanStatus(t, ps, planFile, taskstate.StatusImplementing)

	inst, err := session.NewInstance(session.InstanceOptions{
		Title:      "deferred-complete-W1-T1",
		Path:       t.TempDir(),
		Program:    "claude",
		PlanFile:   planFile,
