	_ = h.nav.AddInstance(inst2)

	msg := metadataResultMsg{
		Results: []instanceMetadata{
			{Title: "auto-advance-failure-W1-T1", TmuxAlive: true},
			{Title: "auto-advance-failure-W1-T2", TmuxAlive: false},
