package cmd

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"

	"github.com/kastheco/kasmos/config"
	"github.com/kastheco/kasmos/config/taskfsm"
	"github.com/kastheco/kasmos/config/taskstate"
	"github.com/kastheco/kasmos/config/taskstore"
	"github.com/kastheco/kasmos/internal/clickup"
	"github.com/spf13/cobra"
)

// executeTaskRegister registers a plan file that exists on disk but isn't
// tracked in plan state yet. It extracts a description from the first markdown
// heading and uses the conventional branch name format.
func executeTaskRegister(plansDir, planFile, branch, topic, description string, store taskstore.Store) error {
	fullPath := filepath.Join(plansDir, planFile)
	if _, err := os.Stat(fullPath); err != nil {
		return fmt.Errorf("plan file not found on disk: %s", fullPath)
	}
	ps, err := loadTaskState(plansDir, store)
	if err != nil {
		return err
	}
	if description == "" {
		data, err := os.ReadFile(fullPath)
		if err != nil {
			return err
		}
		description = strings.TrimSuffix(planFile, ".md")
		for _, line := range strings.Split(string(data), "\n") {
			if strings.HasPrefix(line, "# ") {
				description = strings.TrimPrefix(line, "# ")
				break
			}
		}
	}
	// Default branch: plan/<slug> derived from the plan filename.
	if branch == "" {
		slug := strings.TrimSuffix(planFile, ".md")
		branch = "plan/" + slug
	}
	info, _ := os.Stat(fullPath)
	createdAt := info.ModTime()
	return ps.Create(planFile, description, branch, topic, createdAt)
}

// executeTaskList returns a formatted string listing all plans, optionally
// filtered by status. Exported for testing without cobra plumbing.
func executeTaskList(plansDir, statusFilter string, store taskstore.Store) string {
	ps, err := loadTaskState(plansDir, store)
	if err != nil {
		return fmt.Sprintf("error: %v", err)
	}
	var sb strings.Builder
	for _, info := range ps.List() {
		if statusFilter != "" && string(info.Status) != statusFilter {
			continue
		}
		line := fmt.Sprintf("%-14s %-50s %s", info.Status, info.Filename, info.Branch)
		sb.WriteString(strings.TrimRight(line, " ") + "\n")
	}
	return sb.String()
}

// executeTaskListWithStore returns a formatted string listing all plans from a
// remote store backend. storeURL is the base URL of the plan store server
// (e.g. "http://athena:7433") and project is the project name to query.
func executeTaskListWithStore(storeURL, project string) string {
	store := taskstore.NewHTTPStore(storeURL, project)
	ps, err := taskstate.Load(store, project, "")
	if err != nil {
		return fmt.Sprintf("error: %v", err)
	}
	var sb strings.Builder
	for _, info := range ps.List() {
		line := fmt.Sprintf("%-14s %-50s %s", info.Status, info.Filename, info.Branch)
		sb.WriteString(strings.TrimRight(line, " ") + "\n")
	}
	return sb.String()
}

// executeTaskSetStatus force-overrides a plan's status, bypassing the FSM.
// Requires force=true to prevent accidental misuse.
func executeTaskSetStatus(plansDir, planFile, status string, force bool, store taskstore.Store) error {
	if !force {
		return fmt.Errorf("--force required to override plan status (this bypasses the FSM)")
	}
	ps, err := loadTaskState(plansDir, store)
	if err != nil {
		return err
	}
	return ps.ForceSetStatus(planFile, taskstate.Status(status))
}

// executeTaskTransition applies a named FSM event to a plan and returns the new status.
func executeTaskTransition(plansDir, planFile, event string, store taskstore.Store) (string, error) {
	eventMap := map[string]taskfsm.Event{
		"plan_start":         taskfsm.PlanStart,
		"planner_finished":   taskfsm.PlannerFinished,
		"implement_start":    taskfsm.ImplementStart,
		"implement_finished": taskfsm.ImplementFinished,
		"review_approved":    taskfsm.ReviewApproved,
		"review_changes":     taskfsm.ReviewChangesRequested,
		"request_review":     taskfsm.RequestReview,
		"start_over":         taskfsm.StartOver,
		"reimplement":        taskfsm.Reimplement,
		"cancel":             taskfsm.Cancel,
		"reopen":             taskfsm.Reopen,
	}
	fsmEvent, ok := eventMap[event]
	if !ok {
		names := make([]string, 0, len(eventMap))
		for k := range eventMap {
			names = append(names, k)
		}
		return "", fmt.Errorf("unknown event %q; valid events: %s", event, strings.Join(names, ", "))
	}
	fsm := newFSM(plansDir, store)
	if err := fsm.Transition(planFile, fsmEvent); err != nil {
		return "", err
	}
	ps, err := loadTaskState(plansDir, store)
	if err != nil {
		return "", err
	}
	entry, _ := ps.Entry(planFile)
	return string(entry.Status), nil
}

// executeTaskImplement transitions a plan into implementing state and writes
// a wave signal file so the TUI metadata tick can pick it up.
func executeTaskImplement(plansDir, planFile string, wave int, store taskstore.Store) error {
	if wave < 1 {
		return fmt.Errorf("wave number must be >= 1, got %d", wave)
	}
	fsm := newFSM(plansDir, store)
	ps, err := loadTaskState(plansDir, store)
	if err != nil {
		return err
	}
	entry, ok := ps.Entry(planFile)
	if !ok {
		return fmt.Errorf("plan not found: %s", planFile)
	}
	current := taskfsm.Status(entry.Status)
	// If still in planning, finish that phase first (→ ready).
	if current == taskfsm.StatusPlanning {
		if err := fsm.Transition(planFile, taskfsm.PlannerFinished); err != nil {
			return err
		}
		current = taskfsm.StatusReady
	}
	// Advance to implementing unless already there.
	if current != taskfsm.StatusImplementing {
		if err := fsm.Transition(planFile, taskfsm.ImplementStart); err != nil {
			return err
		}
	}

	// Write the wave signal file consumed by the TUI metadata tick.
	// plansDir is <repo>/docs/plans — go up two levels to reach the repo root.
	repoRoot := filepath.Dir(filepath.Dir(plansDir))
	signalsDir := filepath.Join(repoRoot, ".kasmos", "signals")
	if err := os.MkdirAll(signalsDir, 0o755); err != nil {
		return err
	}
	signalName := fmt.Sprintf("implement-wave-%d-%s", wave, planFile)
	return os.WriteFile(filepath.Join(signalsDir, signalName), nil, 0o644)
}

// executeTaskLinkClickUp iterates all plans in the given project, reads their
// content, parses the ClickUp task ID from the "**Source:** ClickUp <ID>" line,
// and stores it in the clickup_task_id field for any plan that has an ID in its
// content but not yet in the store. Returns the count of plans updated.
func executeTaskLinkClickUp(project string, store taskstore.Store) (int, error) {
	plans, err := store.List(project)
	if err != nil {
		return 0, fmt.Errorf("list plans: %w", err)
	}

	updated := 0
	for _, plan := range plans {
		// Skip plans that already have a ClickUp task ID.
		if plan.ClickUpTaskID != "" {
			continue
		}

		content, err := store.GetContent(project, plan.Filename)
		if err != nil {
			// Non-fatal: skip plans whose content can't be read.
			continue
		}

		taskID := clickup.ParseClickUpTaskID(content)
		if taskID == "" {
			continue
		}

		if err := store.SetClickUpTaskID(project, plan.Filename, taskID); err != nil {
			return updated, fmt.Errorf("set clickup task id for %s: %w", plan.Filename, err)
		}
		updated++
	}

	return updated, nil
}

// NewTaskCmd builds the `kq plan` cobra command tree.
func NewTaskCmd() *cobra.Command {
	planCmd := &cobra.Command{
		Use:   "plan",
		Short: "manage plan lifecycle (list, set-status, transition, implement)",
	}

	// kq plan list
	var statusFilter string
	listCmd := &cobra.Command{
		Use:   "list",
		Short: "list all plans with status",
		RunE: func(cmd *cobra.Command, args []string) error {
			plansDir, err := resolvePlansDir()
			if err != nil {
				return err
			}
			fmt.Print(executeTaskList(plansDir, statusFilter, resolveStore(plansDir)))
			return nil
		},
	}
	listCmd.Flags().StringVar(&statusFilter, "status", "", "filter by status (ready, planning, implementing, reviewing, done, cancelled)")
	planCmd.AddCommand(listCmd)

	// kq plan register
	var branchFlag, topicFlag, descriptionFlag string
	registerCmd := &cobra.Command{
		Use:   "register <plan-file>",
		Short: "register an untracked plan file (sets status to ready)",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			plansDir, err := resolvePlansDir()
			if err != nil {
				return err
			}
			if err := executeTaskRegister(plansDir, args[0], branchFlag, topicFlag, descriptionFlag, resolveStore(plansDir)); err != nil {
				return err
			}
			fmt.Printf("registered: %s → ready\n", args[0])
			return nil
		},
	}
	registerCmd.Flags().StringVar(&branchFlag, "branch", "", "override branch name (default: plan/<slug>)")
	registerCmd.Flags().StringVar(&topicFlag, "topic", "", "assign plan to a topic group (auto-creates topic if needed)")
	registerCmd.Flags().StringVar(&descriptionFlag, "description", "", "override description (default: extracted from first # heading)")
	planCmd.AddCommand(registerCmd)

	// kq plan set-status
	var forceFlag bool
	setStatusCmd := &cobra.Command{
		Use:   "set-status <plan-file> <status>",
		Short: "force-override a plan's status (bypasses FSM)",
		Args:  cobra.ExactArgs(2),
		RunE: func(cmd *cobra.Command, args []string) error {
			plansDir, err := resolvePlansDir()
			if err != nil {
				return err
			}
			if err := executeTaskSetStatus(plansDir, args[0], args[1], forceFlag, resolveStore(plansDir)); err != nil {
				return err
			}
			fmt.Printf("%s → %s\n", args[0], args[1])
			return nil
		},
	}
	setStatusCmd.Flags().BoolVar(&forceFlag, "force", false, "confirm intent to bypass FSM transition rules")
	planCmd.AddCommand(setStatusCmd)

	// kq plan transition
	transitionCmd := &cobra.Command{
		Use:   "transition <plan-file> <event>",
		Short: "apply an FSM event to a plan",
		Args:  cobra.ExactArgs(2),
		RunE: func(cmd *cobra.Command, args []string) error {
			plansDir, err := resolvePlansDir()
			if err != nil {
				return err
			}
			newStatus, err := executeTaskTransition(plansDir, args[0], args[1], resolveStore(plansDir))
			if err != nil {
				return err
			}
			fmt.Printf("%s → %s\n", args[0], newStatus)
			return nil
		},
	}
	planCmd.AddCommand(transitionCmd)

	// kq plan implement
	var waveNum int
	implementCmd := &cobra.Command{
		Use:   "implement <plan-file>",
		Short: "trigger implementation of a specific wave",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			plansDir, err := resolvePlansDir()
			if err != nil {
				return err
			}
			if err := executeTaskImplement(plansDir, args[0], waveNum, resolveStore(plansDir)); err != nil {
				return err
			}
			fmt.Printf("implementation triggered: %s wave %d\n", args[0], waveNum)
			return nil
		},
	}
	implementCmd.Flags().IntVar(&waveNum, "wave", 1, "wave number to trigger (default: 1)")
	planCmd.AddCommand(implementCmd)

	// kq plan link-clickup
	var linkProject string
	linkClickUpCmd := &cobra.Command{
		Use:   "link-clickup",
		Short: "backfill ClickUp task IDs from plan content (parses **Source:** ClickUp <ID> lines)",
		RunE: func(cmd *cobra.Command, args []string) error {
			store, project := resolveStoreConfig("")
			if store == nil {
				var err error
				store, err = localSQLiteStore()
				if err != nil {
					return fmt.Errorf("open local plan store: %w", err)
				}
				defer store.Close()
			}
			if linkProject != "" {
				project = linkProject
			}
			if project == "" {
				plansDir, err := resolvePlansDir()
				if err != nil {
					return err
				}
				project = projectFromPlansDir(plansDir)
			}
			n, err := executeTaskLinkClickUp(project, store)
			if err != nil {
				return err
			}
			fmt.Printf("linked %d plan(s) to ClickUp tasks\n", n)
			return nil
		},
	}
	linkClickUpCmd.Flags().StringVar(&linkProject, "project", "", "project name (default: derived from current directory)")
	planCmd.AddCommand(linkClickUpCmd)

	return planCmd
}

// resolveStoreConfig returns the remote store and project name from config.
// Returns (nil, "") when no remote store is configured.
func resolveStoreConfig(plansDir string) (taskstore.Store, string) {
	cfg := config.LoadConfig()
	if cfg.DatabaseURL == "" {
		return nil, ""
	}
	project := projectFromPlansDir(plansDir)
	store, err := taskstore.NewStoreFromConfig(cfg.DatabaseURL, project)
	if err != nil || store == nil {
		return nil, ""
	}
	return store, project
}

// projectFromPlansDir extracts the repo/project name from a plansDir path.
// plansDir is typically <repo>/docs/plans — go up two levels.
func projectFromPlansDir(plansDir string) string {
	return filepath.Base(filepath.Dir(filepath.Dir(plansDir)))
}

// localSQLiteStore opens (or creates) the local SQLite plan store at the
// canonical path returned by taskstore.ResolvedDBPath(). Used as a fallback
// when no remote store is configured.
func localSQLiteStore() (taskstore.Store, error) {
	dbPath := taskstore.ResolvedDBPath()
	if err := os.MkdirAll(filepath.Dir(dbPath), 0o755); err != nil {
		return nil, fmt.Errorf("create kasmos config dir: %w", err)
	}
	return taskstore.NewSQLiteStore(dbPath)
}

// loadTaskState loads plan state using the store backend.
// When store is nil, falls back to the local SQLite store.
func loadTaskState(plansDir string, store taskstore.Store) (*taskstate.TaskState, error) {
	if store == nil {
		var err error
		store, err = localSQLiteStore()
		if err != nil {
			return nil, fmt.Errorf("open local plan store: %w", err)
		}
	}
	return taskstate.Load(store, projectFromPlansDir(plansDir), plansDir)
}

// newFSM creates a PlanStateMachine backed by the given store.
// When store is nil, falls back to the local SQLite store.
func newFSM(plansDir string, store taskstore.Store) *taskfsm.TaskStateMachine {
	if store == nil {
		var err error
		store, err = localSQLiteStore()
		if err != nil {
			// Panic is acceptable here — this is a CLI tool and the store
			// is required for all operations.
			panic("newFSM: open local plan store: " + err.Error())
		}
	}
	project := projectFromPlansDir(plansDir)
	return taskfsm.New(store, project, plansDir)
}

// resolveStore returns the remote plan store from config, or nil if not
// configured or unreachable.
func resolveStore(plansDir string) taskstore.Store {
	store, _ := resolveStoreConfig(plansDir)
	if store != nil && store.Ping() == nil {
		return store
	}
	return nil
}

// resolvePlansDir resolves docs/plans/ relative to cwd. When the cwd doesn't
// contain docs/plans/ (e.g. when running from a git worktree), it falls back
// to resolving the main repo root via resolveRepoRoot and looks for docs/plans/
// there.
func resolvePlansDir() (string, error) {
	cwd, err := os.Getwd()
	if err != nil {
		return "", fmt.Errorf("get cwd: %w", err)
	}

	// Fast path: docs/plans/ exists relative to cwd (main repo case).
	dir := filepath.Join(cwd, "docs", "plans")
	if _, err := os.Stat(dir); err == nil {
		return dir, nil
	}

	// Fallback: resolve the main repo root (worktree case) and try there.
	root, err := resolveRepoRoot(cwd)
	if err != nil {
		return "", fmt.Errorf("plans directory not found in cwd and cannot resolve repo root: %w", err)
	}
	dir = filepath.Join(root, "docs", "plans")
	if _, err := os.Stat(dir); err != nil {
		return "", fmt.Errorf("plans directory not found: %s", dir)
	}
	return dir, nil
}

// resolveRepoRoot returns the root directory of the git repository that owns
// dir. It handles both regular repositories (where .git is a directory) and
// git worktrees (where .git is a file with a "gitdir:" pointer). On failure it
// falls back to shelling out to `git rev-parse --show-toplevel`.
func resolveRepoRoot(dir string) (string, error) {
	gitPath := filepath.Join(dir, ".git")
	info, err := os.Stat(gitPath)
	if err != nil {
		// .git not found — try git CLI as last resort.
		return resolveRepoRootViaGit(dir)
	}

	if info.IsDir() {
		// Regular repo: .git is a directory, so dir IS the repo root.
		return dir, nil
	}

	// Worktree: .git is a file with content "gitdir: <path>"
	data, err := os.ReadFile(gitPath)
	if err != nil {
		return resolveRepoRootViaGit(dir)
	}
	line := strings.TrimSpace(string(data))
	if !strings.HasPrefix(line, "gitdir: ") {
		return resolveRepoRootViaGit(dir)
	}

	// worktreeGitDir is the per-worktree git dir (e.g. /repo/.git/worktrees/name)
	worktreeGitDir := strings.TrimPrefix(line, "gitdir: ")
	if !filepath.IsAbs(worktreeGitDir) {
		worktreeGitDir = filepath.Join(dir, worktreeGitDir)
	}
	worktreeGitDir = filepath.Clean(worktreeGitDir)

	// commondir contains a relative (or absolute) path back to the main .git dir.
	commondirPath := filepath.Join(worktreeGitDir, "commondir")
	commondirData, err := os.ReadFile(commondirPath)
	if err != nil {
		return resolveRepoRootViaGit(dir)
	}
	commondir := strings.TrimSpace(string(commondirData))

	var mainGitDir string
	if filepath.IsAbs(commondir) {
		mainGitDir = commondir
	} else {
		mainGitDir = filepath.Clean(filepath.Join(worktreeGitDir, commondir))
	}

	// The repo root is the parent of the main .git directory.
	return filepath.Dir(mainGitDir), nil
}

// resolveRepoRootViaGit shells out to git to find the main repository root.
// It uses --git-common-dir (which always points to the main repo's .git) rather
// than --show-toplevel (which returns the worktree checkout path in worktrees).
func resolveRepoRootViaGit(dir string) (string, error) {
	out, err := exec.Command("git", "-C", dir, "rev-parse", "--git-common-dir").Output()
	if err != nil {
		return "", fmt.Errorf("resolve repo root for %s: %w", dir, err)
	}
	gitDir := strings.TrimSpace(string(out))
	if !filepath.IsAbs(gitDir) {
		gitDir = filepath.Join(dir, gitDir)
	}
	// --git-common-dir returns the .git directory; repo root is its parent.
	return filepath.Dir(filepath.Clean(gitDir)), nil
}

package cmd

import (
	"fmt"
	"net/http/httptest"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/kastheco/kasmos/config/taskstate"
	"github.com/kastheco/kasmos/config/taskstore"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// setupTestPlanState creates an in-memory SQLite store pre-populated with two
// test plans and returns the store and a temp plans directory.
// The plans directory is structured as <root>/docs/plans so that
// projectFromPlansDir returns a stable project name derived from <root>.
func setupTestPlanState(t *testing.T) (taskstore.Store, string) {
	t.Helper()
	store := taskstore.NewTestSQLiteStore(t)

	// Build a plans dir with the expected structure so projectFromPlansDir
	// returns a known project name.
	root := t.TempDir()
	plansDir := filepath.Join(root, "docs", "plans")
	require.NoError(t, os.MkdirAll(plansDir, 0o755))

	project := projectFromPlansDir(plansDir)

	require.NoError(t, store.Create(project, taskstore.TaskEntry{
		Filename:    "test-plan.md",
		Status:      taskstore.StatusReady,
		Description: "test plan",
		Branch:      "plan/test-plan",
		CreatedAt:   time.Now(),
	}))
	require.NoError(t, store.Create(project, taskstore.TaskEntry{
		Filename:    "implementing-plan.md",
		Status:      taskstore.Status("implementing"),
		Description: "implementing plan",
		Branch:      "plan/implementing-plan",
		CreatedAt:   time.Now(),
	}))

	return store, plansDir
}

func TestPlanList(t *testing.T) {
	store, dir := setupTestPlanState(t)

	tests := []struct {
		name           string
		statusFilter   string
		wantContains   []string
		wantNotContain []string
	}{
		{
			name:         "all plans",
			wantContains: []string{"test-plan.md", "implementing-plan.md"},
		},
		{
			name:           "filter by ready",
			statusFilter:   "ready",
			wantContains:   []string{"test-plan.md"},
			wantNotContain: []string{"implementing-plan.md"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			output := executeTaskList(dir, tt.statusFilter, store)
			for _, want := range tt.wantContains {
				assert.Contains(t, output, want)
			}
			for _, notWant := range tt.wantNotContain {
				assert.NotContains(t, output, notWant)
			}
		})
	}
}

func TestPlanSetStatus(t *testing.T) {
	store, dir := setupTestPlanState(t)

	// Requires --force
	err := executeTaskSetStatus(dir, "test-plan.md", "done", false, store)
	assert.Error(t, err, "should require --force flag")

	// Valid override
	err = executeTaskSetStatus(dir, "test-plan.md", "done", true, store)
	require.NoError(t, err)

	ps, err := taskstate.Load(store, projectFromPlansDir(dir), dir)
	require.NoError(t, err)
	entry, ok := ps.Entry("test-plan.md")
	require.True(t, ok)
	assert.Equal(t, taskstate.Status("done"), entry.Status)

	// Invalid status
	err = executeTaskSetStatus(dir, "test-plan.md", "bogus", true, store)
	assert.Error(t, err, "should reject invalid status")
}

func TestPlanTransition(t *testing.T) {
	store, dir := setupTestPlanState(t)

	// Valid transition: ready → planning via plan_start
	newStatus, err := executeTaskTransition(dir, "test-plan.md", "plan_start", store)
	require.NoError(t, err)
	assert.Equal(t, "planning", newStatus)

	// Invalid transition (plan is now in "planning" state)
	_, err = executeTaskTransition(dir, "test-plan.md", "review_approved", store)
	assert.Error(t, err)
}

func TestPlanCLI_EndToEnd(t *testing.T) {
	store, dir := setupTestPlanState(t)
	// dir is <root>/docs/plans; signals go to <root>/.kasmos/signals/
	repoRoot := filepath.Dir(filepath.Dir(dir))
	signalsDir := filepath.Join(repoRoot, ".kasmos", "signals")
	require.NoError(t, os.MkdirAll(signalsDir, 0o755))

	// List all
	output := executeTaskList(dir, "", store)
	assert.Contains(t, output, "ready")
	assert.Contains(t, output, "implementing")

	// Transition ready → planning
	status, err := executeTaskTransition(dir, "test-plan.md", "plan_start", store)
	require.NoError(t, err)
	assert.Equal(t, "planning", status)

	// Force set back to ready
	err = executeTaskSetStatus(dir, "test-plan.md", "ready", true, store)
	require.NoError(t, err)

	// Implement with wave signal
	err = executeTaskImplement(dir, "test-plan.md", 2, store)
	require.NoError(t, err)

	// Verify signal file
	entries, _ := os.ReadDir(signalsDir)
	var names []string
	for _, e := range entries {
		names = append(names, e.Name())
	}
	assert.Contains(t, names, "implement-wave-2-test-plan.md")

	// Verify final status
	ps, err := taskstate.Load(store, projectFromPlansDir(dir), dir)
	require.NoError(t, err)
	entry, _ := ps.Entry("test-plan.md")
	assert.Equal(t, taskstate.Status("implementing"), entry.Status)
}

func TestPlanImplement(t *testing.T) {
	store, dir := setupTestPlanState(t)
	// dir is <root>/docs/plans; signals go to <root>/.kasmos/signals/
	repoRoot := filepath.Dir(filepath.Dir(dir))
	signalsDir := filepath.Join(repoRoot, ".kasmos", "signals")
	require.NoError(t, os.MkdirAll(signalsDir, 0o755))

	err := executeTaskImplement(dir, "test-plan.md", 1, store)
	require.NoError(t, err)

	// Verify plan transitioned to implementing
	ps, err := taskstate.Load(store, projectFromPlansDir(dir), dir)
	require.NoError(t, err)
	entry, _ := ps.Entry("test-plan.md")
	assert.Equal(t, taskstate.Status("implementing"), entry.Status)

	// Verify signal file created
	entries, err := os.ReadDir(signalsDir)
	require.NoError(t, err)
	var found bool
	for _, e := range entries {
		if e.Name() == "implement-wave-1-test-plan.md" {
			found = true
		}
	}
	assert.True(t, found, "signal file should exist")
}

func TestPlanRegister(t *testing.T) {
	store, dir := setupTestPlanState(t)
	project := projectFromPlansDir(dir)

	planFile := "new-feature.md"
	require.NoError(t, os.WriteFile(
		filepath.Join(dir, planFile),
		[]byte("# New Feature Plan\n\nSome content."),
		0o644,
	))

	err := executeTaskRegister(dir, planFile, "", "", "", store)
	require.NoError(t, err)

	ps, err := taskstate.Load(store, project, dir)
	require.NoError(t, err)
	entry, ok := ps.Entry(planFile)
	require.True(t, ok)
	assert.Equal(t, taskstate.StatusReady, entry.Status)
	assert.Equal(t, "New Feature Plan", entry.Description)
	assert.Equal(t, "plan/new-feature", entry.Branch)
	assert.Equal(t, "", entry.Topic)
}

func TestPlanRegister_WithTopicAndDescription(t *testing.T) {
	store, dir := setupTestPlanState(t)
	project := projectFromPlansDir(dir)

	planFile := "stub-plan.md"
	require.NoError(t, os.WriteFile(
		filepath.Join(dir, planFile),
		[]byte("# Stub Plan\n"),
		0o644,
	))

	err := executeTaskRegister(dir, planFile, "", "brain phase 1", "Implement circuit breaker", store)
	require.NoError(t, err)

	ps, err := taskstate.Load(store, project, dir)
	require.NoError(t, err)
	entry, ok := ps.Entry(planFile)
	require.True(t, ok)
	assert.Equal(t, taskstate.StatusReady, entry.Status)
	assert.Equal(t, "Implement circuit breaker", entry.Description)
	assert.Equal(t, "brain phase 1", entry.Topic)

	topics := ps.Topics()
	topicNames := make([]string, len(topics))
	for i, topicInfo := range topics {
		topicNames[i] = topicInfo.Name
	}
	assert.Contains(t, topicNames, "brain phase 1")
}

func TestExecutePlanLinkClickUp(t *testing.T) {
	store, err := taskstore.NewSQLiteStore(":memory:")
	require.NoError(t, err)
	defer store.Close()

	// Create a plan with ClickUp source in content.
	require.NoError(t, store.Create("proj", taskstore.TaskEntry{
		Filename: "test.md",
		Status:   taskstore.StatusReady,
	}))
	require.NoError(t, store.SetContent("proj", "test.md", "# Test\n\n**Source:** ClickUp abc123 (https://app.clickup.com/t/abc123)\n"))

	n, err := executeTaskLinkClickUp("proj", store)
	require.NoError(t, err)
	assert.Equal(t, 1, n)

	got, err := store.Get("proj", "test.md")
	require.NoError(t, err)
	assert.Equal(t, "abc123", got.ClickUpTaskID)
}

func TestExecutePlanLinkClickUp_SkipsAlreadyLinked(t *testing.T) {
	store, err := taskstore.NewSQLiteStore(":memory:")
	require.NoError(t, err)
	defer store.Close()

	// Plan already has a ClickUp task ID — should be skipped.
	require.NoError(t, store.Create("proj", taskstore.TaskEntry{
		Filename:      "linked.md",
		Status:        taskstore.StatusReady,
		ClickUpTaskID: "already-set",
	}))
	require.NoError(t, store.SetContent("proj", "linked.md", "# Test\n\n**Source:** ClickUp newid\n"))

	n, err := executeTaskLinkClickUp("proj", store)
	require.NoError(t, err)
	assert.Equal(t, 0, n, "already linked plan should not be updated")
}

func TestResolveRepoRoot_Worktree(t *testing.T) {
	mainRepo := t.TempDir()
	require.NoError(t, os.MkdirAll(filepath.Join(mainRepo, "docs", "plans"), 0o755))
	require.NoError(t, os.MkdirAll(filepath.Join(mainRepo, ".git", "worktrees", "test-wt"), 0o755))

	worktree := t.TempDir()
	gitFile := fmt.Sprintf("gitdir: %s/.git/worktrees/test-wt\n", mainRepo)
	require.NoError(t, os.WriteFile(filepath.Join(worktree, ".git"), []byte(gitFile), 0o644))
	require.NoError(t, os.WriteFile(
		filepath.Join(mainRepo, ".git", "worktrees", "test-wt", "commondir"),
		[]byte("../..\n"), 0o644,
	))

	root, err := resolveRepoRoot(worktree)
	require.NoError(t, err)
	assert.Equal(t, mainRepo, root)
}

func TestResolveRepoRoot_MainRepo(t *testing.T) {
	mainRepo := t.TempDir()
	require.NoError(t, os.MkdirAll(filepath.Join(mainRepo, ".git"), 0o755))

	root, err := resolveRepoRoot(mainRepo)
	require.NoError(t, err)
	assert.Equal(t, mainRepo, root)
}

func TestPlanCLI_FromWorktreeContext(t *testing.T) {
	// Create main repo structure with docs/plans
	mainRepo := t.TempDir()
	plansDir := filepath.Join(mainRepo, "docs", "plans")
	require.NoError(t, os.MkdirAll(plansDir, 0o755))
	require.NoError(t, os.MkdirAll(filepath.Join(mainRepo, ".git", "worktrees", "wt-plans"), 0o755))

	// Create a worktree that has a .git file pointing to the main repo's worktrees dir
	worktree := t.TempDir()
	gitFile := fmt.Sprintf("gitdir: %s/.git/worktrees/wt-plans\n", mainRepo)
	require.NoError(t, os.WriteFile(filepath.Join(worktree, ".git"), []byte(gitFile), 0o644))
	require.NoError(t, os.WriteFile(
		filepath.Join(mainRepo, ".git", "worktrees", "wt-plans", "commondir"),
		[]byte("../..\n"), 0o644,
	))

	// Test resolvePlansDir end-to-end by chdir'ing into the worktree.
	// The worktree has no docs/plans/ — resolvePlansDir must resolve via
	// resolveRepoRoot back to the main repo.
	origDir, err := os.Getwd()
	require.NoError(t, err)
	t.Cleanup(func() { require.NoError(t, os.Chdir(origDir)) })
	require.NoError(t, os.Chdir(worktree))

	resolvedPlansDir, err := resolvePlansDir()
	require.NoError(t, err)
	assert.Equal(t, plansDir, resolvedPlansDir)

	// Populate the store and verify plan operations succeed
	store := taskstore.NewTestSQLiteStore(t)
	project := projectFromPlansDir(resolvedPlansDir)
	require.NoError(t, store.Create(project, taskstore.TaskEntry{
		Filename:    "worktree-plan.md",
		Status:      taskstore.StatusReady,
		Description: "worktree plan",
		Branch:      "plan/worktree-plan",
		CreatedAt:   time.Now(),
	}))

	// executeTaskList should succeed from the resolved plansDir
	output := executeTaskList(resolvedPlansDir, "", store)
	assert.Contains(t, output, "worktree-plan.md")

	// executeTaskSetStatus should succeed
	err = executeTaskSetStatus(resolvedPlansDir, "worktree-plan.md", "done", true, store)
	require.NoError(t, err)

	// executeTaskTransition: reset then transition
	err = executeTaskSetStatus(resolvedPlansDir, "worktree-plan.md", "ready", true, store)
	require.NoError(t, err)
	newStatus, err := executeTaskTransition(resolvedPlansDir, "worktree-plan.md", "plan_start", store)
	require.NoError(t, err)
	assert.Equal(t, "planning", newStatus)
}

// TestPlanList_WithStore verifies that executeTaskListWithStore works with a
// store-backed HTTP server, returning plan entries from the remote store.
func TestPlanList_WithStore(t *testing.T) {
	backend := taskstore.NewTestSQLiteStore(t)
	srv := httptest.NewServer(taskstore.NewHandler(backend))
	defer srv.Close()

	err := backend.Create("test-project", taskstore.TaskEntry{
		Filename: "test.md", Status: "ready", Description: "test plan",
	})
	require.NoError(t, err)

	output := executeTaskListWithStore(srv.URL, "test-project")
	assert.Contains(t, output, "test.md")
	assert.Contains(t, output, "ready")
}

