	n := newTestPanel()
	n.SetData(nil, nil, nil, nil, nil)
	assert.Empty(t, n.rows)
	assert.Equal(t, 0, n.selectedIdx)
}

func TestRebuildRows_PlansWithInstances(t *testing.T) {
	n := newTestPanel()
	plans := []PlanDisplay{
		{Filename: "plan-a.md"},
		{Filename: "plan-b.md"},
	}
